function fixTable(htmlString) {
    var parser = new DOMParser();
    var doc = parser.parseFromString(htmlString, 'text/html');
    var table = doc.getElementsByTagName('table')[0];
    var rows = table.getElementsByTagName('tr');
    for (var i = 0; i < rows.length; i++) {
        var cells = rows[i].getElementsByTagName('td');
        if (cells.length === 0) {
            var header = doc.createElement('th');
            header.textContent = 'Header Not Found';
            rows[i].insertBefore(header, rows[i].firstChild);
        } else if (cells.length > 0 && rows[i].querySelectorAll('th').length === 0) {
            var header = doc.createElement('th');
            header.textContent = 'Header Not Found';
            rows[i].insertBefore(header, cells[0]);
        }
    }
    return table.outerHTML;
}

