class Solution:
    def fix_table(self, html_string):
        from bs4 import BeautifulSoup
        soup = BeautifulSoup(html_string, 'html.parser')
        table = soup.find('table')
        rows = table.find_all('tr')
        for row in rows:
            cells = row.find_all('td')
            if len(cells) === 0:
                var header = soup.new_tag('th')
                header.string = 'Header Not Found'
                row.insert(0, header)
            elif len(cells) > 0 and len(row.find_all('th')) === 0:
                var header = soup.new_tag('th')
                header.string = 'Header Not Found'
                row.insert(0, header)
        return str(table)
